module RefModule(
    input               clk,
    input    [31:0]     in_data,

    output              gpio_sinal,
    output              mem_sinal
);reg                     gpio_reg;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
begin
    if(in_data>1023) gpio_reg <= 1;
    else gpio_reg <= 0;
end

assign gpio_sinal = gpio_reg;
assign mem_sinal = ~gpio_reg;

endmodule
